# Test JSInterpreter
js = dukpy.JSInterpreter()

# Execute code that defines a variable
result = js.evaljs("var x = 42; x")
print(f"Result: {result}")

# Execute code that defines a function
js.evaljs("""
var AJAX_TOKEN = "test123";
""")

# Get the variable value
print(f"AJAX_TOKEN: {js.evaljs('AJAX_TOKEN')}")

# Test with the actual token extraction pattern
js2 = dukpy.JSInterpreter()
# This is similar to what aternos does
code = 'window = {}; window["AJAX_TOKEN"]=("2r" + "KO" + "A1" + "IFdBcHhEM" + "61" + "6cb");'
js2.evaljs(code)
result = js2.evaljs("window.AJAX_TOKEN")
print(f"window.AJAX_TOKEN: {result}")

# Ah but the issue is the js2py interpreter sets up window, Map, setTimeout etc.
# Let's test a more complete setup
js3 = dukpy.JSInterpreter()
js3.evaljs("""
window = {};
window.Map = function(_i){};
window.setTimeout = function(_f, _t){};
window.setInterval = function(_f, _t){};
window.encodeURIComponent = window.Map;
window.document = {};
document.doctype = {};
document.currentScript = {};
document.getElementById = window.Map;
document.prepend = window.Map;
document.append = window.Map;
document.appendChild = window.Map;
window.atob = function(s) {
    return require('base64').atob(s);
};
""")
print("Setup done!")

# Test with a simple token extraction
code = '(() => {window["AJAX_TOKEN"]=("2r" + "KO" + "A1" + "IFdBcHhEM" + "61" + "6cb");})();'
js3.evaljs(code)
print(f"AJAX_TOKEN: {js3.evaljs('window.AJAX_TOKEN')}")
EOF"}

